#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long C,X,Y; scanf("%lld %lld %lld", &C, &X, &Y);
        long long need = C - X; if(need < 0) need = 0;
        printf("%lld\n", need * Y);
    }
    return 0;
}

